128→function splitDocumentIntoChunks(content: string): Array<{ heading?: string; content: string; position: number }> {
129→  const normalized = content.replace(/\r\n/g, "\n").trim();
130→  if (normalized.length === 0) {
131→    throw new HttpError(400, "uploaded file content is empty");
132→  }
133→
134→  const lines = normalized.split("\n");
135→  const sections: Array<{ heading?: string; text: string }> = [];
136→
137→  let currentHeading: string | undefined;
138→  let currentLines: string[] = [];
139→
140→  for (const line of lines) {
141→    const headingMatch = /^(#{1,6})\s+(.+)$/.exec(line.trim());
142→    if (headingMatch) {
143→      if (currentLines.length > 0) {
144→        sections.push({
145→          heading: currentHeading,
146→          text: currentLines.join("\n").trim(),
147→        });
148→      }
149→
150→      currentHeading = headingMatch[2].trim();
151→      currentLines = [];
152→      continue;
153→    }
154→
155→    currentLines.push(line);
156→  }
157→
158→  if (currentLines.length > 0) {
159→    sections.push({
160→      heading: currentHeading,
161→      text: currentLines.join("\n").trim(),
162→    });
163→  }
164→
165→  const maxChunkChars = 2400;
166→  const chunks: Array<{ heading?: string; content: string; position: number }> = [];
167→  let position = 0;
168→
169→  for (const section of sections) {
170→    if (section.text.length === 0) {
171→      continue;
172→    }
173→
174→    if (section.text.length <= maxChunkChars) {
175→      chunks.push({
176→        heading: section.heading,
177→        content: section.text,
178→        position,
179→      });
180→      position += 1;
181→      continue;
182→    }
183→
184→    let cursor = 0;
185→    while (cursor < section.text.length) {
186→      const slice = section.text.slice(cursor, cursor + maxChunkChars).trim();
187→      if (slice.length > 0) {
188→        chunks.push({
189→          heading: section.heading,
190→          content: slice,
191→          position,
192→        });
193→        position += 1;
194→      }
195→      cursor += maxChunkChars;
196→    }
197→  }
198→
199→  if (chunks.length === 0) {
200→    throw new HttpError(400, "uploaded file produced no extractable chunks");
201→  }
202→
203→  return chunks;
204→}
