395→DEFINE FUNCTION fn::conversation_recent($conversation: record<conversation>, $limit: int) {
396→  LET $safe_limit = math::min([math::max([$limit, 1]), 50]);
397→  RETURN SELECT id, role, text, createdAt
398→  FROM message
399→  WHERE conversation = $conversation
400→  ORDER BY createdAt DESC
401→  LIMIT $safe_limit;
