 9→export function isFuzzyNameMatch(a: string, b: string): boolean {
10→  if (a.length === 0 || b.length === 0) {
11→    return false;
12→  }
13→
14→  if (a === b) {
15→    return true;
16→  }
17→
18→  return a.includes(b) || b.includes(a);
19→}
