  1→import type { ExtractionPromptEntity, ExtractionPromptRelationship } from "./schema";
  2→
  3→export function shouldStoreExtraction(confidence: number, threshold = 0.6): boolean {
  4→  return confidence >= threshold;
  5→}
  6→
  7→export function shouldDisplayExtraction(confidence: number, threshold = 0.85): boolean {
  8→  return confidence >= threshold;
  9→}
 10→
 11→export function hasGroundedEvidence(evidence: string, sourceText: string): boolean {
 12→  const trimmedEvidence = evidence.trim();
 13→  if (trimmedEvidence.length === 0) {
 14→    return false;
 15→  }
 16→
 17→  return sourceText.includes(trimmedEvidence);
 18→}
 19→
 20→export function postValidateEntities(input: {
 21→  entities: ExtractionPromptEntity[];
 22→  sourceText: string;
 23→  storeThreshold: number;
 24→}): ExtractionPromptEntity[] {
 25→  const byTempId = new Map<string, ExtractionPromptEntity>();
 26→
 27→  for (const entity of input.entities) {
 28→    const tempId = entity.tempId.trim();
 29→    if (tempId.length === 0) {
 30→      continue;
 31→    }
 32→
 33→    const text = entity.text.trim();
 34→    if (text.length < 3) {
 35→      continue;
 36→    }
 37→
 38→    const evidence = entity.evidence.trim();
 39→    if (evidence.length === 0) {
 40→      continue;
 41→    }
 42→
 43→    if (!shouldStoreExtraction(entity.confidence, input.storeThreshold)) {
 44→      continue;
 45→    }
 46→
 47→    if (!hasGroundedEvidence(evidence, input.sourceText)) {
 48→      continue;
 49→    }
 50→
 51→    const assigneeName = ("assignee_name" in entity ? entity.assignee_name : undefined)?.trim();
 52→    const resolvedFromMessageId = ("resolvedFromMessageId" in entity ? entity.resolvedFromMessageId : undefined)?.trim();
 53→    const normalized: ExtractionPromptEntity = {
 54→      ...entity,
 55→      tempId,
 56→      text,
 57→      evidence,
 58→      ...(assigneeName ? { assignee_name: assigneeName } : {}),
 59→      ...(resolvedFromMessageId ? { resolvedFromMessageId } : {}),
 60→    };
 61→
 62→    const existing = byTempId.get(tempId);
 63→    if (!existing || normalized.confidence > existing.confidence) {
 64→      byTempId.set(tempId, normalized);
 65→    }
 66→  }
 67→
 68→  return [...byTempId.values()];
 69→}
 70→
 71→export function postValidateRelationships(input: {
 72→  relationships: ExtractionPromptRelationship[];
 73→  storeThreshold: number;
 74→}): ExtractionPromptRelationship[] {
 75→  return input.relationships
 76→    .filter((relationship) => shouldStoreExtraction(relationship.confidence, input.storeThreshold))
 77→    .map((relationship) => {
 78→      const kind = relationship.kind.trim();
 79→      const fromTempId = relationship.fromTempId.trim();
 80→      const toTempId = relationship.toTempId.trim();
 81→      const fromText = relationship.fromText.trim();
 82→      const toText = relationship.toText.trim();
 83→
 84→      return {
 85→        ...relationship,
 86→        kind,
 87→        fromTempId,
 88→        toTempId,
 89→        fromText,
 90→        toText,
 91→      };
 92→    })
 93→    .filter(
 94→      (relationship) =>
 95→        relationship.kind.length > 0 &&
 96→        relationship.fromTempId.length > 0 &&
 97→        relationship.toTempId.length > 0 &&
 98→        relationship.fromText.length > 0 &&
 99→        relationship.toText.length > 0,
100→    );
