 17→export async function upsertGraphEntity(input: {
 18→  surreal: Surreal;
 19→  embeddingModel: any;
 20→  embeddingDimension: number;
 21→  extractionModelId: string;
 22→  workspaceRecord: RecordId<"workspace", string>;
 23→  workspaceProjects: ProjectScopeRow[];
 24→  sourceRecord: SourceRecord;
 25→  sourceKind: "message" | "document_chunk";
 26→  promptText: string;
 27→  extracted: ExtractionPromptEntity & { kind: PersistableExtractableEntityKind };
 28→  sourceMessageRecord?: RecordId<"message", string>;
 29→  sourceChunkRecord?: RecordId<"document_chunk", string>;
 30→  resolvedFromMessageRecord?: RecordId<"message", string>;
 31→  now: Date;
 32→}): Promise<{ record: GraphEntityRecord; text: string; kind: PersistableExtractableEntityKind; created: boolean }> {
 33→  const candidateEmbedding = await createEmbedding(input.embeddingModel, input.embeddingDimension, input.extracted.text);
 34→  const candidates = await loadWorkspaceKindCandidates(input.surreal, input.workspaceRecord, input.extracted.kind);
 35→  const normalizedExtractedText = normalizeName(input.extracted.text);
 36→
 37→  const exactNameCandidate = candidates.find((candidate) => normalizeName(candidate.text) === normalizedExtractedText);
 38→  if (exactNameCandidate) {
 39→    const mergedText = await maybeUpgradeMergedEntityName(
 40→      input.surreal,
 41→      input.extracted.kind,
 42→      input.extracted.text,
 43→      exactNameCandidate,
 44→      input.now,
 45→    );
 46→
 47→    await createProvenanceEdge({
 48→      surreal: input.surreal,
 49→      sourceRecord: input.sourceRecord,
 50→      targetRecord: exactNameCandidate.id,
 51→      confidence: input.extracted.confidence,
 52→      model: input.extractionModelId,
 53→      now: input.now,
 54→      fromText: input.extracted.text,
 55→      evidence: input.extracted.evidence,
 56→      evidenceSourceRecord: input.sourceMessageRecord,
 57→      resolvedFromRecord: input.resolvedFromMessageRecord,
 58→    });
 59→
 60→    return {
 61→      record: exactNameCandidate.id,
 62→      text: mergedText,
 63→      kind: input.extracted.kind,
 64→      created: false,
 65→    };
 66→  }
 67→
 68→  let bestCandidate: CandidateEntityRow | undefined;
 69→  let bestSimilarity = -1;
 70→
 71→  for (const candidate of candidates) {
 72→    if (!candidate.embedding || !candidateEmbedding) {
 73→      continue;
 74→    }
 75→
 76→    const similarity = cosineSimilarity(candidateEmbedding, candidate.embedding);
 77→    if (similarity > bestSimilarity) {
 78→      bestSimilarity = similarity;
 79→      bestCandidate = candidate;
 80→    }
 81→  }
 82→
 83→  const fuzzyMatch = bestCandidate
 84→    ? isFuzzyNameMatch(normalizeName(input.extracted.text), normalizeName(bestCandidate.text))
 85→    : false;
 86→
 87→  if (bestCandidate && bestSimilarity > 0.95 && fuzzyMatch) {
 88→    const mergedText = await maybeUpgradeMergedEntityName(
 89→      input.surreal,
 90→      input.extracted.kind,
 91→      input.extracted.text,
 92→      bestCandidate,
 93→      input.now,
 94→    );
 95→
 96→    await createProvenanceEdge({
 97→      surreal: input.surreal,
 98→      sourceRecord: input.sourceRecord,
 99→      targetRecord: bestCandidate.id,
100→      confidence: input.extracted.confidence,
101→      model: input.extractionModelId,
102→      now: input.now,
103→      fromText: input.extracted.text,
104→      evidence: input.extracted.evidence,
105→      evidenceSourceRecord: input.sourceMessageRecord,
106→      resolvedFromRecord: input.resolvedFromMessageRecord,
107→    });
108→
109→    return {
110→      record: bestCandidate.id,
111→      text: mergedText,
112→      kind: input.extracted.kind,
113→      created: false,
114→    };
115→  }
116→
117→  const entityRecord = new RecordId(input.extracted.kind, randomUUID()) as GraphEntityRecord;
118→  await input.surreal.create(entityRecord).content(
119→    buildEntityRecordContent(
120→      input.extracted.kind,
121→      input.extracted.text,
122→      input.extracted.confidence,
123→      input.now,
124→      candidateEmbedding,
125→      input.sourceMessageRecord,
126→    ),
127→  );
128→
129→  await createProvenanceEdge({
130→    surreal: input.surreal,
131→    sourceRecord: input.sourceRecord,
132→    targetRecord: entityRecord,
133→    confidence: input.extracted.confidence,
134→    model: input.extractionModelId,
135→    now: input.now,
136→    fromText: input.extracted.text,
137→    evidence: input.extracted.evidence,
138→    evidenceSourceRecord: input.sourceMessageRecord,
139→    resolvedFromRecord: input.resolvedFromMessageRecord,
140→  });
141→
142→  if (input.extracted.kind === "project") {
143→    await ensureWorkspaceProjectEdge(input.surreal, input.workspaceRecord, entityRecord as RecordId<"project", string>, input.now);
144→    input.workspaceProjects.push({
145→      id: entityRecord as RecordId<"project", string>,
146→      name: input.extracted.text,
147→    });
148→  }
149→
150→  if (input.extracted.kind === "feature") {
151→    const projectRecord = resolveEntityProject(input.extracted.text, input.promptText, input.workspaceProjects);
152→    if (projectRecord) {
153→      await ensureProjectFeatureEdge(input.surreal, projectRecord, entityRecord as RecordId<"feature", string>, input.now);
154→    }
155→  }
156→
157→  if (input.extracted.kind === "task" || input.extracted.kind === "decision" || input.extracted.kind === "question") {
158→    const projectRecord = resolveEntityProject(input.extracted.text, input.promptText, input.workspaceProjects);
159→    if (projectRecord) {
160→      await input.surreal.relate(entityRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
161→        added_at: input.now,
162→      }).output("after");
163→    }
164→  }
165→
166→  if (bestCandidate && bestSimilarity >= 0.8 && bestSimilarity <= 0.95) {
167→    await input.surreal.relate(entityRecord, new RecordId("entity_relation", randomUUID()), bestCandidate.id, {
168→      kind: "POSSIBLE_DUPLICATE",
169→      confidence: bestSimilarity,
170→      ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
171→      ...(input.sourceChunkRecord ? { source_chunk: input.sourceChunkRecord } : {}),
172→      extracted_at: input.now,
173→      created_at: input.now,
174→      from_text: input.extracted.text,
175→      to_text: bestCandidate.text,
176→    }).output("after");
177→  }
178→
179→  return {
180→    record: entityRecord,
181→    text: input.extracted.text,
182→    kind: input.extracted.kind,
183→    created: true,
184→  };
185→}
