320→export async function loadWorkspaceKindCandidates(
321→  surreal: Surreal,
322→  workspaceRecord: RecordId<"workspace", string>,
323→  kind: ExtractableEntityKind,
324→): Promise<CandidateEntityRow[]> {
325→  if (kind === "project") {
326→    const [rows] = await surreal
327→      .query<[CandidateEntityRow[]]>(
328→        "SELECT id, name AS text, embedding FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
329→        { workspace: workspaceRecord },
330→      )
331→      .collect<[CandidateEntityRow[]]>();
332→    return rows;
333→  }
334→
335→  if (kind === "person") {
336→    const [rows] = await surreal
337→      .query<[CandidateEntityRow[]]>(
338→        "SELECT id, name AS text, embedding FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
339→        { workspace: workspaceRecord },
340→      )
341→      .collect<[CandidateEntityRow[]]>();
342→    return rows;
343→  }
344→
345→  if (kind === "feature") {
346→    const [rows] = await surreal
347→      .query<[CandidateEntityRow[]]>(
348→        [
349→          "SELECT id, name AS text, embedding",
350→          "FROM feature",
351→          "WHERE id IN (",
352→          "  SELECT VALUE out",
353→          "  FROM has_feature",
354→          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
355→          ");",
356→        ].join(" "),
357→        { workspace: workspaceRecord },
358→      )
359→      .collect<[CandidateEntityRow[]]>();
360→    return rows;
361→  }
362→
363→  if (kind === "task") {
364→    const [rows] = await surreal
365→      .query<[CandidateEntityRow[]]>(
366→        [
367→          "SELECT id, title AS text, embedding",
368→          "FROM task",
369→          "WHERE id IN (",
370→          "  SELECT VALUE `in`",
371→          "  FROM belongs_to",
372→          "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
373→          ")",
374→          "OR source_message IN (",
375→          "  SELECT VALUE id",
376→          "  FROM message",
377→          "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
378→          ");",
379→        ].join(" "),
380→        { workspace: workspaceRecord },
381→      )
382→      .collect<[CandidateEntityRow[]]>();
383→    return uniqueCandidateRows(rows);
384→  }
385→
386→  if (kind === "decision") {
387→    const [rows] = await surreal
388→      .query<[CandidateEntityRow[]]>(
389→        [
390→          "SELECT id, summary AS text, embedding",
391→          "FROM decision",
392→          "WHERE id IN (",
393→          "  SELECT VALUE `in`",
394→          "  FROM belongs_to",
395→          "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
396→          ")",
397→          "OR source_message IN (",
398→          "  SELECT VALUE id",
399→          "  FROM message",
400→          "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
401→          ");",
402→        ].join(" "),
403→        { workspace: workspaceRecord },
404→      )
405→      .collect<[CandidateEntityRow[]]>();
406→    return uniqueCandidateRows(rows);
407→  }
408→
409→  const [rows] = await surreal
410→    .query<[CandidateEntityRow[]]>(
411→      [
412→        "SELECT id, text AS text, embedding",
413→        "FROM question",
414→        "WHERE id IN (",
415→        "  SELECT VALUE `in`",
416→        "  FROM belongs_to",
417→        "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
418→        ")",
419→        "OR source_message IN (",
420→        "  SELECT VALUE id",
421→        "  FROM message",
422→        "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
423→        ");",
424→      ].join(" "),
425→      { workspace: workspaceRecord },
426→    )
427→    .collect<[CandidateEntityRow[]]>();
428→  return uniqueCandidateRows(rows);
429→}
430→
431→function uniqueCandidateRows(rows: CandidateEntityRow[]): CandidateEntityRow[] {
432→  const byId = new Map<string, CandidateEntityRow>();
433→  for (const row of rows) {
434→    byId.set(row.id.id as string, row);
435→  }
436→  return [...byId.values()];
437→}
