 95→        sourceKind: input.sourceKind,
 96→        promptText: input.promptText,
 97→        extracted: extracted as ExtractionPromptEntity & { kind: Exclude<EntityKind, "workspace" | "person"> },
 98→        sourceMessageRecord: input.sourceMessageRecord,
 99→        sourceChunkRecord: input.sourceChunkRecord,
100→        resolvedFromMessageRecord,
101→        now: input.now,
102→      });
103→
104→      entityByTempId.set(extracted.tempId, {
105→        record: persisted.record,
106→        text: persisted.text,
107→        id: persisted.record.id as string,
108→        kind: persisted.kind,
109→      });
110→
111→      persistedEntities.push({
112→        id: persisted.record.id as string,
113→        kind: persisted.kind,
114→        text: persisted.text,
115→        confidence: extracted.confidence,
116→        sourceKind: input.sourceKind,
117→        sourceId: input.sourceRecord.id as string,
118→      });
119→
120→      seeds.push({
121→        id: persisted.record.id as string,
122→        kind: persisted.kind,
123→        text: persisted.text,
124→        confidence: extracted.confidence,
125→        sourceKind: input.sourceKind,
126→        sourceId: input.sourceRecord.id as string,
127→        ...(input.sourceLabel ? { sourceLabel: input.sourceLabel } : {}),
128→      });
129→
130→      if (persisted.created) {
131→        embeddingTargets.push({
132→          record: persisted.record,
133→          text: persisted.text,
134→        });
135→      }
136→
137→      const assigneeName = "assignee_name" in extracted ? extracted.assignee_name : undefined;
138→      if (assigneeName) {
139→        const attribution = await applyAssigneeReference({
140→          surreal: input.surreal,
141→          workspaceRecord: input.workspaceRecord,
