 1→import type { EntityKind, ExtractedEntity, ExtractedRelationship } from "../../shared/contracts";
 2→import { normalizeName } from "./normalize";
 3→import { shouldDisplayExtraction } from "./validation";
 4→
 5→type ExtractableEntityKind = Exclude<EntityKind, "workspace">;
 6→
 7→type CardEntity = {
 8→  kind: ExtractableEntityKind;
 9→  name: string;
10→  confidence: number;
11→  status: "captured";
