 20→export function postValidateEntities(input: {
 21→  entities: ExtractionPromptEntity[];
 22→  sourceText: string;
 23→  storeThreshold: number;
 24→}): ExtractionPromptEntity[] {
 25→  const byTempId = new Map<string, ExtractionPromptEntity>();
 26→
 27→  for (const entity of input.entities) {
 28→    const tempId = entity.tempId.trim();
 29→    if (tempId.length === 0) {
 30→      continue;
 31→    }
 32→
 33→    const text = entity.text.trim();
 34→    if (text.length < 3) {
 35→      continue;
 36→    }
 37→
 38→    const evidence = entity.evidence.trim();
 39→    if (evidence.length === 0) {
 40→      continue;
 41→    }
 42→
 43→    if (!shouldStoreExtraction(entity.confidence, input.storeThreshold)) {
 44→      continue;
 45→    }
 46→
 47→    if (!hasGroundedEvidence(evidence, input.sourceText)) {
 48→      continue;
 49→    }
 50→
 51→    const assigneeName = ("assignee_name" in entity ? entity.assignee_name : undefined)?.trim();
 52→    const resolvedFromMessageId = ("resolvedFromMessageId" in entity ? entity.resolvedFromMessageId : undefined)?.trim();
 53→    const normalized: ExtractionPromptEntity = {
 54→      ...entity,
 55→      tempId,
 56→      text,
 57→      evidence,
 58→      ...(assigneeName ? { assignee_name: assigneeName } : {}),
 59→      ...(resolvedFromMessageId ? { resolvedFromMessageId } : {}),
 60→    };
 61→
 62→    const existing = byTempId.get(tempId);
 63→    if (!existing || normalized.confidence > existing.confidence) {
 64→      byTempId.set(tempId, normalized);
 65→    }
 66→  }
 67→
 68→  return [...byTempId.values()];
 69→}
