18→): string | undefined {
19→  const summaryEntities = new Map<string, CardEntity>();
20→
21→  for (const entity of [...entities].sort((a, b) => b.confidence - a.confidence)) {
22→    if (entity.kind === "workspace" || !shouldDisplayExtraction(entity.confidence, displayThreshold)) {
