30→
31→    const key = `${entity.kind}:${normalizeName(name)}`;
32→    if (!summaryEntities.has(key)) {
33→      summaryEntities.set(key, {
34→        kind: entity.kind as ExtractableEntityKind,
35→        name,
36→        confidence: entity.confidence,
37→        status: "captured",
38→      });
39→    }
40→  }
41→
42→  const cards = [...summaryEntities.values()].slice(0, 6);
43→  if (cards.length === 0) {
44→    return undefined;
45→  }
46→
47→  const componentSpec = cards.length === 1
48→    ? {
49→        type: "EntityCard",
50→        props: cards[0],
51→      }
52→    : {
53→        type: "ExtractionSummary",
54→        props: {
