155→export function resolveEntityProject(
156→  entityText: string,
157→  promptText: string,
158→  projects: ProjectScopeRow[],
159→): RecordId<"project", string> | undefined {
160→  if (projects.length === 0) {
161→    return undefined;
162→  }
163→
164→  if (projects.length === 1) {
165→    return projects[0].id;
166→  }
167→
168→  const haystack = `${promptText}\n${entityText}`.toLowerCase();
169→  const matchingProjects = projects.filter((project) => haystack.includes(project.name.toLowerCase()));
170→
171→  if (matchingProjects.length !== 1) {
172→    return undefined;
173→  }
174→
175→  return matchingProjects[0].id;
176→}
