 22→export type ConversationGroupInput = {
 23→  id: string;
 24→  title?: string;
 25→  updatedAt: string;
 26→  touchedBy: Array<{ projectId: string; entityCount: number }>;
 27→};
 28→
 29→export type GroupingResult = {
 30→  groups: Map<string, ConversationSidebarItem[]>;
 31→  unlinked: ConversationSidebarItem[];
 32→};
 33→
 34→/**
 35→ * Groups conversations by dominant project using strict majority heuristic.
 36→ * A conversation is assigned to a project only if that project's entity_count
 37→ * is strictly greater than half of the total entity count across all projects.
 38→ */
 39→export function groupConversationsByProject(conversations: ConversationGroupInput[]): GroupingResult {
 40→  const groups = new Map<string, ConversationSidebarItem[]>();
 41→  const unlinked: ConversationSidebarItem[] = [];
 42→
 43→  for (const conv of conversations) {
 44→    const item: ConversationSidebarItem = {
 45→      id: conv.id,
 46→      title: conv.title ?? "Untitled",
 47→      updatedAt: conv.updatedAt,
 48→    };
 49→
 50→    if (conv.touchedBy.length === 0) {
 51→      unlinked.push(item);
 52→      continue;
 53→    }
 54→
 55→    const total = conv.touchedBy.reduce((sum, edge) => sum + edge.entityCount, 0);
 56→    let topEdge = conv.touchedBy[0];
 57→    for (const edge of conv.touchedBy) {
 58→      if (edge.entityCount > topEdge.entityCount) {
 59→        topEdge = edge;
 60→      }
 61→    }
 62→
 63→    if (topEdge.entityCount > total / 2) {
 64→      const existing = groups.get(topEdge.projectId) ?? [];
 65→      existing.push(item);
 66→      groups.set(topEdge.projectId, existing);
 67→    } else {
 68→      unlinked.push(item);
 69→    }
 70→  }
 71→
 72→  return { groups, unlinked };
 73→}
