 75→/**
 76→ * Derives the initial title for a conversation from the first user message.
 77→ */
 78→export function deriveMessageTitle(text: string): string {
 79→  const trimmed = text.trim();
 80→  if (trimmed.length <= 72) {
 81→    return trimmed;
 82→  }
 83→  return `${trimmed.slice(0, 69)}...`;
 84→}
