 86→export type TitleUpgradeInput = {
 87→  titleSource?: "message" | "entity";
 88→  entityTexts: Array<{ kind: string; text: string }>;
 89→  dominantProjectName?: string;
 90→};
 91→
 92→/**
 93→ * Determines whether a conversation title should be upgraded and returns
 94→ * the new title if so. Returns undefined if no upgrade should happen.
 95→ */
 96→export function computeTitleUpgrade(input: TitleUpgradeInput): string | undefined {
 97→  if (input.titleSource !== "message") {
 98→    return undefined;
 99→  }
100→
101→  const qualifying = input.entityTexts.filter(
102→    (entity) => entity.kind !== "person" && entity.kind !== "workspace",
103→  );
104→
105→  if (qualifying.length < 3) {
106→    return undefined;
107→  }
108→
109→  if (input.dominantProjectName) {
110→    return deriveMessageTitle(input.dominantProjectName);
111→  }
112→
113→  // Use the most common entity text as fallback
114→  const counts = new Map<string, number>();
115→  for (const entity of qualifying) {
116→    const key = entity.text.toLowerCase();
117→    counts.set(key, (counts.get(key) ?? 0) + 1);
118→  }
119→
120→  let bestText = qualifying[0].text;
121→  let bestCount = 0;
122→  for (const [key, count] of counts) {
123→    if (count > bestCount) {
124→      bestCount = count;
125→      bestText = qualifying.find((e) => e.text.toLowerCase() === key)?.text ?? bestText;
126→    }
127→  }
128→
129→  return deriveMessageTitle(bestText);
130→}
