212→/**
213→ * Refreshes the touched_by edges for a conversation based on its extraction_relation rows.
214→ */
215→export async function refreshConversationTouchedBy(
216→  surreal: Surreal,
217→  conversationRecord: RecordId<"conversation", string>,
218→): Promise<void> {
219→  const [extractionRows] = await surreal
220→    .query<[ExtractionEdgeRow[]]>(
221→      "SELECT out, extracted_at FROM extraction_relation WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation);",
222→      { conversation: conversationRecord },
223→    )
224→    .collect<[ExtractionEdgeRow[]]>();
225→
226→  // Aggregate: projectId -> { uniqueEntityIds, earliestExtractedAt }
227→  const projectAgg = new Map<string, { entityIds: Set<string>; earliestAt: Date }>();
228→
229→  for (const row of extractionRows) {
230→    const projects = await resolveEntityToProjects(surreal, row.out);
231→    const extractedAt = row.extracted_at instanceof Date ? row.extracted_at : new Date(row.extracted_at as string);
232→    const entityId = `${row.out.tb}:${row.out.id}`;
233→
234→    for (const projectRecord of projects) {
235→      const projectId = projectRecord.id as string;
236→      const existing = projectAgg.get(projectId);
237→      if (existing) {
238→        existing.entityIds.add(entityId);
239→        if (extractedAt < existing.earliestAt) {
240→          existing.earliestAt = extractedAt;
241→        }
242→      } else {
243→        projectAgg.set(projectId, {
244→          entityIds: new Set([entityId]),
245→          earliestAt: extractedAt,
246→        });
247→      }
248→    }
249→  }
250→
251→  // Load existing touched_by edges for this conversation
252→  const [existingEdges] = await surreal
253→    .query<[TouchedByRow[]]>(
254→      "SELECT id, `in`, out, entity_count, first_mention_at FROM touched_by WHERE out = $conversation;",
255→      { conversation: conversationRecord },
256→    )
257→    .collect<[TouchedByRow[]]>();
258→
259→  const existingByProject = new Map<string, TouchedByRow>();
260→  for (const edge of existingEdges) {
261→    existingByProject.set(edge.in.id as string, edge);
262→  }
263→
264→  // Upsert edges for current project aggregations
265→  for (const [projectId, agg] of projectAgg) {
266→    const existing = existingByProject.get(projectId);
267→    const entityCount = agg.entityIds.size;
268→
269→    if (existing) {
270→      await surreal.update(existing.id).merge({
271→        entity_count: entityCount,
272→        first_mention_at: agg.earliestAt,
273→      });
274→      existingByProject.delete(projectId);
275→    } else {
276→      const projectRecord = new RecordId("project", projectId);
277→      await surreal.relate(
278→        projectRecord,
279→        new RecordId("touched_by", randomUUID()),
280→        conversationRecord,
281→        {
282→          first_mention_at: agg.earliestAt,
283→          entity_count: entityCount,
284→        },
285→      ).output("after");
286→    }
287→  }
288→
289→  // Remove stale edges (projects no longer represented)
290→  for (const staleEdge of existingByProject.values()) {
291→    await surreal.delete(staleEdge.id);
292→  }
293→
294→  logInfo("conversation.touched_by.refreshed", "Refreshed touched_by edges", {
295→    conversationId: conversationRecord.id as string,
296→    projectCount: projectAgg.size,
297→    removedCount: existingByProject.size,
298→  });
299→}
