301→/**
302→ * Upgrades a conversation title if conditions are met (title_source === "message",
303→ * >= 3 qualifying entities extracted).
304→ */
305→export async function maybeUpgradeConversationTitle(
306→  surreal: Surreal,
307→  conversationRecord: RecordId<"conversation", string>,
308→): Promise<void> {
309→  const conversation = await surreal.select<{
310→    title?: string;
311→    title_source?: "message" | "entity";
312→  }>(conversationRecord);
313→
314→  if (!conversation || conversation.title_source !== "message") {
315→    return;
316→  }
317→
318→  // Count qualifying extracted entities for this conversation
319→  const [entityRows] = await surreal
320→    .query<[Array<{ out: GraphEntityRecord }>]>(
321→      "SELECT out FROM extraction_relation WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation);",
322→      { conversation: conversationRecord },
323→    )
324→    .collect<[Array<{ out: GraphEntityRecord }>]>();
325→
326→  const uniqueEntities = new Map<string, { kind: string; text: string }>();
327→  for (const row of entityRows) {
328→    const key = `${row.out.tb}:${row.out.id}`;
329→    if (!uniqueEntities.has(key)) {
330→      uniqueEntities.set(key, { kind: row.out.tb, text: "" });
331→    }
332→  }
333→
334→  const qualifying = [...uniqueEntities.values()].filter(
335→    (e) => e.kind !== "person" && e.kind !== "workspace",
336→  );
337→
338→  if (qualifying.length < 3) {
339→    return;
340→  }
341→
342→  // Check for dominant project via touched_by
343→  const [touchedByRows] = await surreal
344→    .query<[Array<{ in: RecordId<"project", string>; entity_count: number }>]>(
345→      "SELECT `in`, entity_count FROM touched_by WHERE out = $conversation;",
346→      { conversation: conversationRecord },
347→    )
348→    .collect<[Array<{ in: RecordId<"project", string>; entity_count: number }>]>();
349→
350→  let dominantProjectName: string | undefined;
351→  if (touchedByRows.length > 0) {
352→    const total = touchedByRows.reduce((sum, row) => sum + row.entity_count, 0);
353→    let topRow = touchedByRows[0];
354→    for (const row of touchedByRows) {
355→      if (row.entity_count > topRow.entity_count) {
356→        topRow = row;
357→      }
358→    }
359→
360→    if (topRow.entity_count > total / 2) {
361→      const project = await surreal.select<{ name: string }>(topRow.in);
362→      if (project) {
363→        dominantProjectName = project.name;
364→      }
365→    }
366→  }
367→
368→  // Get entity texts for fallback title
369→  const entityTexts: Array<{ kind: string; text: string }> = [];
370→  for (const [, entry] of uniqueEntities) {
371→    entityTexts.push(entry);
372→  }
373→
374→  // Need actual texts from entities
375→  const entityTextRows: Array<{ kind: string; text: string }> = [];
376→  for (const row of entityRows) {
377→    const kind = row.out.tb;
378→    if (kind === "person" || kind === "workspace") continue;
379→
380→    const textField = kind === "task" ? "title" : kind === "decision" ? "summary" : "text";
381→    const entity = await surreal.select<Record<string, string>>(row.out);
382→    if (entity) {
383→      const text = entity[textField] ?? entity.name ?? "";
384→      entityTextRows.push({ kind, text });
385→    }
386→  }
387→
388→  const newTitle = computeTitleUpgrade({
389→    titleSource: "message",
390→    entityTexts: entityTextRows,
391→    dominantProjectName,
392→  });
393→
394→  if (newTitle) {
395→    await surreal.update(conversationRecord).merge({
396→      title: newTitle,
397→      title_source: "entity" as const,
398→    });
399→
400→    logInfo("conversation.title.upgraded", "Upgraded conversation title", {
401→      conversationId: conversationRecord.id as string,
402→      newTitle,
403→    });
404→  }
405→}
