407→// ── Sidebar builder ─────────────────────────────────────────────────────
408→
409→type ConversationSidebarRow = {
410→  id: RecordId<"conversation", string>;
411→  title?: string;
412→  updatedAt: Date | string;
413→};
414→
415→type FeatureActivityRow = {
416→  featureId: RecordId<"feature", string>;
417→  featureName: string;
418→  latestActivityAt: Date | string;
419→};
420→
421→export async function buildWorkspaceConversationSidebar(
422→  surreal: Surreal,
423→  workspaceRecord: RecordId<"workspace", string>,
424→): Promise<WorkspaceConversationSidebarResponse> {
425→  // Load all conversations for this workspace
426→  const [conversationRows] = await surreal
427→    .query<[ConversationSidebarRow[]]>(
428→      "SELECT id, title, updatedAt FROM conversation WHERE workspace = $workspace ORDER BY updatedAt DESC;",
429→      { workspace: workspaceRecord },
430→    )
431→    .collect<[ConversationSidebarRow[]]>();
432→
433→  // Load all touched_by edges for these conversations
434→  const conversationIds = conversationRows.map((row) => row.id);
435→  const [touchedByRows] = await surreal
436→    .query<[TouchedByRow[]]>(
437→      "SELECT id, `in`, out, entity_count, first_mention_at FROM touched_by WHERE out IN $conversations;",
438→      { conversations: conversationIds },
439→    )
440→    .collect<[TouchedByRow[]]>();
441→
442→  // Build touched_by lookup by conversation
443→  const touchedByMap = new Map<string, Array<{ projectId: string; entityCount: number }>>();
444→  for (const row of touchedByRows) {
445→    const convId = row.out.id as string;
446→    const existing = touchedByMap.get(convId) ?? [];
447→    existing.push({ projectId: row.in.id as string, entityCount: row.entity_count });
448→    touchedByMap.set(convId, existing);
449→  }
450→
451→  // Build conversation input for grouping
452→  const conversationInputs: ConversationGroupInput[] = conversationRows.map((row) => ({
453→    id: row.id.id as string,
454→    title: row.title,
455→    updatedAt: toIsoString(row.updatedAt),
456→    touchedBy: touchedByMap.get(row.id.id as string) ?? [],
457→  }));
458→
459→  const { groups, unlinked } = groupConversationsByProject(conversationInputs);
460→
461→  // Load project names and build groups
462→  const projectGroups: ProjectConversationGroup[] = [];
463→  for (const [projectId, conversations] of groups) {
464→    const projectRecord = new RecordId("project", projectId);
465→    const project = await surreal.select<{ name: string }>(projectRecord);
466→    if (!project) continue;
467→
468→    const featureActivity = await loadProjectFeatureActivity(surreal, projectRecord, conversations);
469→
470→    projectGroups.push({
471→      projectId,
472→      projectName: project.name,
473→      conversations,
474→      featureActivity,
475→    });
476→  }
477→
478→  return { groups: projectGroups, unlinked };
479→}
