481→async function loadProjectFeatureActivity(
482→  surreal: Surreal,
483→  projectRecord: RecordId<"project", string>,
484→  _conversations: ConversationSidebarItem[],
485→): Promise<ProjectFeatureActivity[]> {
486→  // Get features for this project with latest extraction activity
487→  const [rows] = await surreal
488→    .query<[FeatureActivityRow[]]>(
489→      [
490→        "SELECT out.id AS featureId, out.name AS featureName, math::max(extracted_at) AS latestActivityAt",
491→        "FROM extraction_relation",
492→        "WHERE out IN (SELECT VALUE out FROM has_feature WHERE `in` = $project)",
493→        "GROUP BY out",
494→        "ORDER BY latestActivityAt DESC",
495→        "LIMIT 5;",
496→      ].join(" "),
497→      { project: projectRecord },
498→    )
499→    .collect<[FeatureActivityRow[]]>();
500→
501→  return rows.map((row) => ({
502→    featureId: (row.featureId as unknown as RecordId<"feature", string>).id as string,
503→    featureName: row.featureName,
504→    latestActivityAt: toIsoString(row.latestActivityAt),
505→  }));
506→}
