 53→export async function ensureWorkspaceProjectEdge(
 54→  surreal: Surreal,
 55→  workspaceRecord: RecordId<"workspace", string>,
 56→  projectRecord: RecordId<"project", string>,
 57→  now: Date,
 58→): Promise<void> {
 59→  const [edgeRows] = await surreal
 60→    .query<[HasProjectRow[]]>(
 61→      "SELECT id FROM has_project WHERE `in` = $workspace AND out = $project LIMIT 1;",
 62→      {
 63→        workspace: workspaceRecord,
 64→        project: projectRecord,
 65→      },
 66→    )
 67→    .collect<[HasProjectRow[]]>();
 68→
 69→  if (edgeRows.length === 0) {
 70→    await surreal.relate(workspaceRecord, new RecordId("has_project", randomUUID()), projectRecord, {
 71→      added_at: now,
 72→    }).output("after");
 73→  }
 74→}
