337→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
338→  LET $query = string::lowercase(string::trim($q));
339→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
340→  LET $workspace_conversations = SELECT VALUE id FROM conversation WHERE workspace = $workspace;
341→  LET $workspace_messages = SELECT VALUE id FROM message WHERE conversation IN $workspace_conversations;
342→  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;
343→
344→  LET $task_rows = SELECT
345→    id,
346→    "task" AS kind,
347→    title AS text,
348→    extraction_confidence AS confidence,
349→    source_message AS sourceMessage,
350→    created_at
351→  FROM task
352→  WHERE source_message != NONE
353→    AND source_message IN $workspace_messages
354→    AND extraction_confidence != NONE
355→    AND id IN $project_entity_ids
356→    AND string::contains(string::lowercase(title), $query)
357→  ORDER BY created_at DESC
358→  LIMIT $safe_limit;
359→
360→  LET $decision_rows = SELECT
361→    id,
362→    "decision" AS kind,
363→    summary AS text,
364→    extraction_confidence AS confidence,
365→    source_message AS sourceMessage,
366→    created_at
367→  FROM decision
