369→    AND source_message IN $workspace_messages
370→    AND extraction_confidence != NONE
371→    AND id IN $project_entity_ids
372→    AND string::contains(string::lowercase(summary), $query)
373→  ORDER BY created_at DESC
374→  LIMIT $safe_limit;
375→
376→  LET $question_rows = SELECT
377→    id,
378→    "question" AS kind,
379→    text AS text,
380→    extraction_confidence AS confidence,
381→    source_message AS sourceMessage,
382→    created_at
