 10→export async function extractStructuredGraph(input: {
 11→  extractionModel: any;
 12→  conversationHistory: MessageContextRow[];
 13→  currentMessage?: MessageContextRow;
 14→  graphContext: ExtractionGraphContextRow[];
 15→  sourceText: string;
 16→  onboarding: boolean;
 17→  heading?: string;
 18→}): Promise<ExtractionPromptOutput> {
 19→  const startedAt = performance.now();
 20→  logInfo("extraction.generate.started", "Structured extraction started", {
 21→    onboarding: input.onboarding,
 22→    hasHeading: input.heading !== undefined,
 23→    contextMessageCount: input.conversationHistory.length,
 24→    hasCurrentMessage: input.currentMessage !== undefined,
 25→    graphContextCount: input.graphContext.length,
 26→    sourceLength: input.sourceText.length,
 27→  });
 28→
 29→  try {
 30→    const extractionOutput = await generateObject({
 31→      model: input.extractionModel,
 32→      schema: extractionResultSchema,
 33→      system: buildExtractionSystemPrompt({ onboarding: input.onboarding }),
 34→      prompt: [
 35→        "Conversation history (reference resolution only):",
 36→        formatExtractionConversationHistory(input.conversationHistory),
 37→        "",
 38→        "Current message (extract only from this text when message metadata exists):",
 39→        formatExtractionCurrentMessage(input.currentMessage, input.sourceText),
 40→        "",
 41→        "Resolved-from lineage constraints:",
 42→        formatResolvedFromConstraints(input.currentMessage, input.conversationHistory),
 43→        "",
 44→        "Existing graph context (semantic index of prior extracted entities):",
 45→        formatExtractionGraphContext(input.graphContext),
 46→        input.heading ? `Section heading: ${input.heading}` : "",
 47→        "",
 48→        "Current source text:",
 49→        input.sourceText,
 50→      ]
 51→        .filter((line) => line.length > 0)
 52→        .join("\n"),
 53→    });
 54→
 55→    const output = extractionOutput.object as ExtractionPromptOutput;
 56→    logInfo("extraction.generate.completed", "Structured extraction completed", {
 57→      onboarding: input.onboarding,
 58→      entityCount: output.entities.length,
 59→      relationshipCount: output.relationships.length,
 60→      toolCount: output.tools.length,
 61→      durationMs: elapsedMs(startedAt),
 62→    });
 63→
 64→    return output;
 65→  } catch (error) {
 66→    logError("extraction.generate.failed", "Structured extraction failed", error, {
 67→      onboarding: input.onboarding,
 68→      durationMs: elapsedMs(startedAt),
 69→    });
 70→    throw error;
 71→  }
 72→}
 73→
 74→function formatExtractionConversationHistory(rows: MessageContextRow[]): string {
 75→  if (rows.length === 0) {
 76→    return "(no prior messages)";
 77→  }
 78→
 79→  return rows.map((row) => `[message:${row.id.id as string}] ${row.role.toUpperCase()}: ${row.text}`).join("\n");
 80→}
 81→
 82→function formatExtractionCurrentMessage(currentMessage: MessageContextRow | undefined, sourceText: string): string {
 83→  if (!currentMessage) {
 84→    return `(no message metadata; source text: ${sourceText})`;
 85→  }
 86→
 87→  return `[message:${currentMessage.id.id as string}] ${currentMessage.role.toUpperCase()}: ${currentMessage.text}`;
 88→}
 89→
 90→function formatExtractionGraphContext(rows: ExtractionGraphContextRow[]): string {
 91→  if (rows.length === 0) {
 92→    return "(no prior extracted entities)";
 93→  }
 94→
 95→  return rows
 96→    .map((row) => {
 97→      const table = row.id.tb;
 98→      return `[entity:${table}:${row.id.id as string}] ${row.kind}: ${row.text} (confidence ${row.confidence.toFixed(2)}, source message ${row.sourceMessage.id as string})`;
 99→    })
100→    .join("\n");
101→}
102→
103→function formatResolvedFromConstraints(
104→  currentMessage: MessageContextRow | undefined,
105→  conversationHistory: MessageContextRow[],
106→): string {
107→  if (!currentMessage) {
108→    return "Current message id unavailable; omit resolvedFromMessageId.";
109→  }
110→
111→  const currentMessageId = currentMessage.id.id as string;
112→  if (conversationHistory.length === 0) {
113→    return [
114→      `Current message id (forbidden for resolvedFromMessageId): ${currentMessageId}`,
115→      "Allowed resolvedFromMessageId values (history only): none",
116→      "Omit resolvedFromMessageId.",
117→    ].join("\n");
118→  }
119→
120→  const historyMessageIds = conversationHistory.map((row) => row.id.id as string);
121→  return [
122→    `Current message id (forbidden for resolvedFromMessageId): ${currentMessageId}`,
123→    `Allowed resolvedFromMessageId values (history only): ${historyMessageIds.join(", ")}`,
124→    "Use one of the allowed ids exactly, or omit resolvedFromMessageId.",
125→  ].join("\n");
126→}
