218→async function applyAssigneeReference(input: {
219→  surreal: Surreal;
220→  workspaceRecord: RecordId<"workspace", string>;
221→  entityRecord: GraphEntityRecord;
222→  entityKind: Exclude<EntityKind, "workspace" | "person">;
223→  assigneeName: string;
224→  now: Date;
225→}): Promise<{ resolved: boolean; assigneeName: string }> {
226→  const assigneeName = input.assigneeName.trim();
227→  if (assigneeName.length === 0) {
228→    return { resolved: true, assigneeName };
229→  }
230→
231→  const personRecord = await findWorkspacePersonByName({
232→    surreal: input.surreal,
233→    workspaceRecord: input.workspaceRecord,
234→    personName: assigneeName,
235→  });
236→
237→  const patch = resolvePersonAttributionPatch({
238→    targetKind: input.entityKind,
239→    assigneeName,
240→    ...(personRecord ? { personRecordId: personRecord.id as string } : {}),
241→  });
242→
243→  if (patch.kind === "feature") {
244→    if (patch.field === "owner" && personRecord) {
245→      await input.surreal.update(input.entityRecord as RecordId<"feature", string>).merge({
246→        owner: personRecord,
247→        updated_at: input.now,
248→      });
249→      return { resolved: true, assigneeName };
250→    }
251→
252→    await input.surreal.update(input.entityRecord as RecordId<"feature", string>).merge({
253→      owner_name: patch.value,
254→      updated_at: input.now,
255→    });
256→    return { resolved: false, assigneeName };
257→  }
258→
259→  if (patch.kind === "task") {
260→    if (patch.field === "owner" && personRecord) {
261→      await input.surreal.update(input.entityRecord as RecordId<"task", string>).merge({
262→        owner: personRecord,
263→        updated_at: input.now,
264→      });
265→      return { resolved: true, assigneeName };
266→    }
267→
268→    await input.surreal.update(input.entityRecord as RecordId<"task", string>).merge({
269→      owner_name: patch.value,
270→      updated_at: input.now,
271→    });
272→    return { resolved: false, assigneeName };
273→  }
274→
275→  if (patch.kind === "decision") {
276→    if (patch.field === "decided_by" && personRecord) {
277→      await input.surreal.update(input.entityRecord as RecordId<"decision", string>).merge({
278→        decided_by: personRecord,
279→        updated_at: input.now,
280→      });
281→      return { resolved: true, assigneeName };
282→    }
283→
284→    await input.surreal.update(input.entityRecord as RecordId<"decision", string>).merge({
285→      decided_by_name: patch.value,
286→      updated_at: input.now,
287→    });
288→    return { resolved: false, assigneeName };
289→  }
290→
291→  if (patch.field === "assigned_to" && personRecord) {
292→    await input.surreal.update(input.entityRecord as RecordId<"question", string>).merge({
293→      assigned_to: personRecord,
294→      updated_at: input.now,
295→    });
296→    return { resolved: true, assigneeName };
297→  }
298→
299→  await input.surreal.update(input.entityRecord as RecordId<"question", string>).merge({
300→    assigned_to_name: patch.value,
301→    updated_at: input.now,
302→  });
303→  return { resolved: false, assigneeName };
304→}
