105→const factualityScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
106→  name: "factuality",
107→  description: "Average factual grounding score for extracted entity texts against matched provenance evidence snippets.",
108→  scorer: async ({ input, output }) => {
109→    if (output.extractedEntities.length === 0) {
110→      return { score: 1 };
111→    }
112→
113→    let total = 0;
114→    for (const entity of output.extractedEntities) {
115→      const snippet = resolveEntityEvidenceSnippet(entity.text, output.evidenceRows, input.input);
116→      const result = await Factuality({
117→        input: snippet,
118→        output: entity.text,
119→        expected: snippet,
120→        model: autoevalModel,
121→      });
122→      total += result.score ?? 0;
123→    }
124→
125→    return { score: total / output.extractedEntities.length };
126→  },
127→});
