172→function scoreByName(
173→  scores: Array<{ name: string; score: number | null }>,
174→  name: string,
175→): number {
176→  const match = scores.find((score) => score.name === name);
177→  if (!match || match.score === null || Number.isNaN(match.score)) {
178→    throw new Error(`Missing score for scorer: ${name}`);
179→  }
180→
181→  return match.score;
182→}
183→
184→function formatScoreCell(value: number): string {
185→  return value.toFixed(2);
186→}
