188→function computeWeightedAverage(
189→  intent: GoldenCaseIntent,
190→  scores: Array<{ name: string; score: number | null }>,
191→): number {
192→  const weights = intentScoreWeights[intent];
193→  if (!weights) {
194→    throw new Error(`Unknown golden case intent: ${intent}`);
195→  }
196→
197→  let weightedTotal = 0;
198→  let weightTotal = 0;
199→  for (const [scorerName, weight] of Object.entries(weights)) {
200→    if (weight <= 0) {
201→      continue;
202→    }
203→
204→    weightedTotal += scoreByName(scores, scorerName) * weight;
205→    weightTotal += weight;
206→  }
207→
208→  if (weightTotal === 0) {
209→    throw new Error(`No scorer weights configured for intent: ${intent}`);
210→  }
211→
212→  return weightedTotal / weightTotal;
213→}
