215→function resolveEntityEvidenceSnippet(
216→  entityText: string,
217→  evidenceRows: Array<{ evidence?: string; fromText?: string; model?: string }>,
218→  fallbackInput: string,
219→): string {
220→  const normalizedEntityText = normalizeForSubstring(entityText);
221→  const matched = evidenceRows.find((row) => normalizeForSubstring(row.fromText ?? "") === normalizedEntityText);
222→  const snippet = matched?.evidence ?? evidenceRows[0]?.evidence ?? fallbackInput;
223→  return snippet.trim().length > 0 ? snippet : fallbackInput;
224→}
