226→async function runCase(testCase: GoldenCase): Promise<ExtractionEvalOutput> {
227→  const cacheKey = buildCaseCacheKey(extractionModel, testCase);
228→  const cached = resultCache[cacheKey];
229→  if (cached) {
230→    return {
231→      ...cached,
232→      extractedTools: cached.extractedTools ?? [],
233→      extractedRelations: cached.extractedRelations ?? [],
234→    };
235→  }
236→
237→  const { workspaceRecord, projectRecord, conversationRecord, ownerPersonCount } = await seedWorkspace(runtime.surreal);
238→  const conversationId = conversationRecord.id as string;
239→  const seededContext = testCase.context ?? [];
240→  const contextMessageIds = seededContext.length > 0
241→    ? await seedConversationContext(runtime.surreal, conversationRecord, seededContext)
242→    : [];
243→
244→  if (testCase.workspace_seed && testCase.workspace_seed.length > 0) {
245→    await seedGraphEntities(runtime.surreal, workspaceRecord, projectRecord, conversationRecord, testCase.workspace_seed);
246→  }
247→
248→  const userMessageRecord = await seedUserMessage(runtime.surreal, conversationRecord, testCase.input);
249→
250→  const extractionConversationContext = await loadExtractionConversationContext({
251→    surreal: runtime.surreal,
252→    conversationId,
253→    currentMessageRecord: userMessageRecord,
254→  });
255→  const extractionGraphContext = await loadConversationGraphContext(runtime.surreal, conversationId, 60);
256→
257→  const extraction = await extractStructuredGraph({
258→    extractionModel: runtime.extractionModel,
259→    conversationHistory: extractionConversationContext.conversationHistory,
260→    currentMessage: extractionConversationContext.currentMessage,
261→    graphContext: extractionGraphContext,
262→    sourceText: testCase.input,
263→    onboarding: true,
264→  });
265→
266→  const now = new Date();
267→  const persistence = await persistExtractionOutput({
268→    surreal: runtime.surreal,
269→    embeddingModel: runtime.embeddingModel,
270→    embeddingDimension: runtime.config.embeddingDimension,
271→    extractionModelId: runtime.config.extractionModelId,
272→    extractionStoreThreshold: runtime.config.extractionStoreThreshold,
273→    workspaceRecord,
274→    sourceRecord: userMessageRecord as SourceRecord,
275→    sourceKind: "message",
276→    sourceLabel: testCase.input.slice(0, 140),
277→    promptText: testCase.input,
278→    output: extraction,
279→    sourceMessageRecord: userMessageRecord,
280→    extractionHistoryMessageIds: extractionConversationContext.conversationHistory.map(
281→      (row) => row.id.id as string,
282→    ),
283→    now,
284→  });
285→
286→  await appendExtractedTools(runtime.surreal, workspaceRecord, persistence.tools, now);
287→
288→  const [evidenceRows] = await runtime.surreal
289→    .query<[Array<{
290→      evidence?: string;
291→      from_text?: string;
292→      model?: string;
293→      evidence_source?: RecordId<"message", string>;
294→      resolved_from?: RecordId<"message", string>;
295→    }>]>(
296→      "SELECT evidence, from_text, model, evidence_source, resolved_from FROM extraction_relation WHERE `in` = $source;",
297→      { source: userMessageRecord },
298→    )
299→    .collect<[Array<{
300→      evidence?: string;
301→      from_text?: string;
302→      model?: string;
303→      evidence_source?: RecordId<"message", string>;
304→      resolved_from?: RecordId<"message", string>;
305→    }>]>();
306→
307→  const personCount = await loadWorkspacePeopleCount(runtime.surreal, workspaceRecord);
308→  const [workspaceToolRows] = await runtime.surreal
309→    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
310→      workspace: workspaceRecord,
311→    })
312→    .collect<[Array<{ tools?: string[] }>]>();
313→  const extractedTools = workspaceToolRows[0]?.tools ?? [];
314→
315→  const [relationRows] = await runtime.surreal
316→    .query<[Array<{
317→      kind: string;
318→      in: { tb: string };
319→      out: { tb: string };
320→      from_text: string;
321→      to_text: string;
322→      confidence: number;
323→    }>]>(
324→      "SELECT kind, `in`, out, from_text, to_text, confidence FROM entity_relation WHERE source_message = $source AND kind != 'POSSIBLE_DUPLICATE';",
325→      { source: userMessageRecord },
326→    )
327→    .collect<[Array<{
328→      kind: string;
329→      in: { tb: string };
330→      out: { tb: string };
331→      from_text: string;
332→      to_text: string;
333→      confidence: number;
334→    }>]>();
335→
336→  const output: ExtractionEvalOutput = {
337→    caseId: testCase.id,
338→    input: testCase.input,
339→    userMessageId: userMessageRecord.id as string,
340→    contextMessageIds,
341→    extractedEntities: persistence.entities.map((e) => ({
342→      kind: e.kind,
343→      text: e.text,
344→      confidence: e.confidence,
345→    })),
346→    extractedTools,
347→    personCount,
348→    ownerPersonCount,
349→    evidenceRows: evidenceRows.map((row) => ({
350→      evidence: row.evidence,
351→      fromText: row.from_text,
352→      model: row.model,
353→      evidenceSourceId: row.evidence_source?.id as string | undefined,
354→      resolvedFromId: row.resolved_from?.id as string | undefined,
355→    })),
356→    extractedRelations: relationRows.map((row) => ({
357→      kind: row.kind,
358→      fromKind: row.in.tb,
359→      fromText: row.from_text,
360→      toKind: row.out.tb,
361→      toText: row.to_text,
362→      confidence: row.confidence,
363→    })),
364→  };
365→
366→  resultCache[cacheKey] = output;
367→  saveCache(cachePath, resultCache);
368→  return output;
369→}
