411→function buildCaseCacheKey(modelId: string, testCase: GoldenCase): string {
412→  const cacheVersion = "classification-v3";
413→  const caseHash = createHash("sha256").update(JSON.stringify(testCase)).digest("hex").slice(0, 24);
414→  return `${cacheVersion}:${modelId}:${testCase.id}:${caseHash}`;
