254→function buildEntityRecordContent(
255→  kind: PersistableExtractableEntityKind,
256→  text: string,
257→  confidence: number,
258→  now: Date,
259→  embedding?: number[],
260→  sourceMessageRecord?: RecordId<"message", string>,
261→): Record<string, unknown> {
262→  if (kind === "project") {
263→    return {
264→      name: text,
265→      status: "active",
266→      ...(embedding ? { embedding } : {}),
267→      created_at: now,
268→      updated_at: now,
269→    };
270→  }
271→
272→  if (kind === "feature") {
273→    return {
274→      name: text,
275→      status: "active",
276→      ...(embedding ? { embedding } : {}),
277→      created_at: now,
278→      updated_at: now,
279→    };
280→  }
281→
282→  if (kind === "task") {
283→    return {
284→      title: text,
285→      status: "open",
286→      extraction_confidence: confidence,
287→      extracted_at: now,
288→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
289→      ...(embedding ? { embedding } : {}),
290→      created_at: now,
291→      updated_at: now,
292→    };
293→  }
294→
295→  if (kind === "decision") {
296→    return {
297→      summary: text,
298→      status: "extracted",
299→      extraction_confidence: confidence,
300→      extracted_at: now,
301→      ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
302→      ...(embedding ? { embedding } : {}),
303→      created_at: now,
304→      updated_at: now,
305→    };
306→  }
307→
308→  return {
309→    text,
310→    status: "open",
311→    extraction_confidence: confidence,
312→    extracted_at: now,
313→    ...(sourceMessageRecord ? { source_message: sourceMessageRecord } : {}),
314→    ...(embedding ? { embedding } : {}),
