 5→export const entityPrecisionScorer = createScorer<GoldenCase, ExtractionEvalOutput, GoldenCase>({
 6→  name: "entity-precision",
 7→  description: "Percent of extracted entities that match expected entities by kind and text/text_contains expectation.",
 8→  scorer: ({ output, expected }) => {
 9→    const expectedEntities = expected?.expectedEntities ?? [];
10→    if (output.extractedEntities.length === 0) {
11→      return { score: expectedEntities.length === 0 ? 1 : 0 };
12→    }
13→
14→    let matched = 0;
15→    for (const entity of output.extractedEntities) {
16→      const found = expectedEntities.some(
17→        (candidate: GoldenCase["expectedEntities"][number]) => matchesExpectedEntity(candidate, entity, 0.5),
18→      );
19→      if (found) {
20→        matched += 1;
21→      }
22→    }
23→
24→    return { score: matched / output.extractedEntities.length };
25→  },
26→});
