 26→export async function setupEvalRuntime(suiteName: string): Promise<EvalRuntime> {
 27→  const namespace = `eval_${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 28→  const database = `${suiteName}_${Math.floor(Math.random() * 100000)}`;
 29→
 30→  const surreal = new Surreal();
 31→  await surreal.connect(surrealUrl);
 32→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 33→
 34→  await surreal.query(`DEFINE NAMESPACE ${namespace};`).catch((error) => {
 35→    if (!isAlreadyExistsError(error)) throw error;
 36→  });
 37→  await surreal.use({ namespace, database });
 38→  await surreal.query(`REMOVE DATABASE ${database};`).catch(() => undefined);
 39→  await surreal.query(`DEFINE DATABASE ${database};`).catch((error) => {
 40→    if (!isAlreadyExistsError(error)) throw error;
 41→  });
 42→  await surreal.use({ namespace, database });
 43→
 44→  const schemaSql = readFileSync(schemaPath, "utf8");
 45→  await surreal.query(schemaSql).catch((error) => {
 46→    if (!isAlreadyExistsError(error)) throw error;
 47→  });
 48→
 49→  const openRouterApiKey = requireEnv("OPENROUTER_API_KEY");
 50→  const extractionModelId = process.env.EXTRACTION_MODEL ?? "anthropic/claude-3.5-haiku";
 51→  const assistantModelId = process.env.ASSISTANT_MODEL ?? "anthropic/claude-3.5-haiku";
 52→  const embeddingModelId = requireEnv("OPENROUTER_EMBEDDING_MODEL");
 53→  const embeddingDimension = Number(requireEnv("EMBEDDING_DIMENSION"));
 54→  const extractionStoreThreshold = Number(process.env.EXTRACTION_STORE_THRESHOLD ?? "0.3");
 55→  const extractionDisplayThreshold = Number(process.env.EXTRACTION_DISPLAY_THRESHOLD ?? "0.5");
 56→
 57→  const openrouter = createOpenRouter({ apiKey: openRouterApiKey });
 58→  const extractionModel = openrouter(extractionModelId, { plugins: [{ id: "response-healing" }] });
 59→  const assistantModel = openrouter(assistantModelId, { plugins: [{ id: "response-healing" }] });
 60→  const embeddingModel = openrouter.textEmbeddingModel(embeddingModelId);
 61→
 62→  const config: ServerConfig = {
 63→    openRouterApiKey,
 64→    assistantModelId,
 65→    extractionModelId,
 66→    embeddingModelId,
 67→    embeddingDimension,
 68→    extractionStoreThreshold,
 69→    extractionDisplayThreshold,
 70→    surrealUrl,
 71→    surrealUsername,
 72→    surrealPassword,
 73→    surrealNamespace: namespace,
 74→    surrealDatabase: database,
 75→    port: 0,
 76→  };
 77→
 78→  return {
 79→    surreal,
 80→    extractionModel,
 81→    embeddingModel,
 82→    assistantModel,
 83→    config,
 84→    namespace,
 85→    database,
 86→  };
 87→}
