199→export async function seedGraphEntities(
200→  surreal: Surreal,
201→  workspaceRecord: RecordId<"workspace", string>,
202→  projectRecord: RecordId<"project", string>,
203→  conversationRecord: RecordId<"conversation", string>,
204→  seeds: WorkspaceSeedItem[],
205→): Promise<void> {
206→  const now = new Date();
207→  const seedMessageRecord = new RecordId("message", randomUUID());
208→  await surreal.create(seedMessageRecord).content({
209→    conversation: conversationRecord,
210→    role: "assistant",
211→    text: "Workspace seed context.",
212→    createdAt: new Date(now.getTime() - 60_000),
213→  });
214→
215→  for (const seed of seeds) {
216→    const entityRecord = new RecordId(seed.kind, randomUUID());
217→    await surreal.create(entityRecord).content(buildSeedEntityContent(seed.kind, seed.text, now));
218→
219→    await surreal.relate(seedMessageRecord, new RecordId("extraction_relation", randomUUID()), entityRecord, {
220→      confidence: 0.95,
221→      extracted_at: now,
222→      created_at: now,
223→      model: "seed",
224→      from_text: seed.text,
225→      evidence: seed.text,
226→      evidence_source: seedMessageRecord,
227→    }).output("after");
228→
229→    if (seed.kind === "feature") {
230→      await surreal.relate(projectRecord, new RecordId("has_feature", randomUUID()), entityRecord as RecordId<"feature", string>, {
231→        added_at: now,
232→      }).output("after");
233→    }
234→
235→    if (seed.kind === "task" || seed.kind === "decision" || seed.kind === "question") {
236→      await surreal.relate(entityRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
237→        added_at: now,
238→      }).output("after");
239→    }
240→
241→    if (seed.kind === "project") {
242→      await surreal.relate(workspaceRecord, new RecordId("has_project", randomUUID()), entityRecord as RecordId<"project", string>, {
243→        added_at: now,
244→      }).output("after");
245→    }
246→  }
247→}
