249→function buildSeedEntityContent(kind: string, text: string, now: Date): Record<string, unknown> {
250→  const base = { created_at: now, updated_at: now };
251→  if (kind === "project") return { ...base, name: text, status: "active" };
252→  if (kind === "feature") return { ...base, name: text, status: "active" };
253→  if (kind === "task") return { ...base, title: text, status: "open" };
254→  if (kind === "decision") return { ...base, summary: text, status: "extracted" };
255→  return { ...base, text, status: "open" };
256→}
