258→export function createEventCollector(): SseRegistry & { getEvents(messageId: string): StreamEvent[] } {
259→  const events = new Map<string, StreamEvent[]>();
260→  return {
261→    registerMessage(messageId: string) {
262→      events.set(messageId, []);
263→    },
264→    handleStreamRequest(_messageId: string): Response {
265→      throw new Error("handleStreamRequest not available in eval mode");
266→    },
267→    emitEvent(messageId: string, event: StreamEvent) {
268→      events.get(messageId)?.push(event);
269→    },
270→    getEvents(messageId: string): StreamEvent[] {
271→      return events.get(messageId) ?? [];
272→    },
273→  };
274→}
