 1→export function normalizeName(value: string): string {
 2→  return value
 3→    .toLowerCase()
 4→    .replace(/[^a-z0-9\s]/g, " ")
 5→    .replace(/\s+/g, " ")
 6→    .trim();
 7→}
 8→
 9→export function isFuzzyNameMatch(a: string, b: string): boolean {
10→  if (a.length === 0 || b.length === 0) {
11→    return false;
12→  }
13→
14→  if (a === b) {
15→    return true;
16→  }
17→
18→  return a.includes(b) || b.includes(a);
19→}
